import random

def beta_sample(alpha, beta_param):
    """Sample from Beta(alpha, beta) using Gamma variates."""
    x = random.gammavariate(alpha, 1.0)
    y = random.gammavariate(beta_param, 1.0)
    return x / (x + y)

